{
  "stream_id": "checkout",
  "window": {"start": "2026-02-22", "end": "2026-05-23", "days": 90},
  "customer_anchor": {"start_event": "support_ticket_opened", "end_event": "feature_visible_in_prod"},
  "flow_metrics_by_type": {
    "feature": {"lead_time_days": 28, "cycle_time_days": 4, "throughput_per_week": 6, "wip": 12, "complete_and_accurate_pct": 0.82, "sample_size": 62},
    "defect":  {"lead_time_days": 9,  "cycle_time_days": 2, "throughput_per_week": 14, "wip": 6,  "complete_and_accurate_pct": 0.91, "sample_size": 110},
    "risk":    {"lead_time_days": 18, "cycle_time_days": 3, "throughput_per_week": 2,  "wip": 4,  "complete_and_accurate_pct": 0.95, "sample_size": 55},
    "debt":    {"lead_time_days": 22, "cycle_time_days": 5, "throughput_per_week": 3,  "wip": 8,  "complete_and_accurate_pct": 0.85, "sample_size": 58}
  },
  "dora": {
    "deployment_frequency": {"human_prs": 220, "bot_prs": 90},
    "change_lead_time_minutes": 95, "change_failure_rate": 0.07, "mttr_minutes": 38,
    "trend_window_quarters": 3, "tier_label": "high", "tier_label_delta_vs_prior": "+1 vs prior quarter"
  },
  "constraint": {
    "stage": "design-review",
    "evidence": "design-review stage has WIP=10 and cycle_time 6.2d; feature lead_time 28d minus cycle 4d implies 24d queue upstream of code; ID-linked items confirm review is the dominant wait state",
    "samples_per_type": {"feature": 62, "defect": 110, "risk": 55, "debt": 58}
  },
  "experiments": [
    {"name": "WIP cap on design-review = 3", "expected_lift": "feature lead_time -25% (28d -> 21d)", "cost": "1 designer day/week facilitation", "rank": 1},
    {"name": "Async-first review with 1-business-day SLA", "expected_lift": "feature lead_time -15%", "cost": "0 (process change)", "rank": 2},
    {"name": "Add designer FTE", "expected_lift": "throughput +30%", "cost": "$140k/yr loaded", "rank": 3}
  ]
}
